package com.calmspace.ui.player

import android.util.Base64
import com.calmspace.R

data class PlaybackTrack(
    val id: String,
    val title: String,
    val rawResId: Int = 0,   // default for user tracks
    val envelopeHopMs: Int = 0,
    val envelopeDbfsLevels: FloatArray = floatArrayOf(),
    val uriString: String? = null
)

object PrecomputedPlaybackTracks {
    val tracks: List<PlaybackTrack> = listOf(
        PlaybackTrack(
            id = "rain_from_indoors",
            title = "Rain From Indoors",
            rawResId = R.raw.rain_from_indoors_perfect_loop,
            envelopeHopMs = 10,
            envelopeDbfsLevels = decodeDbfsLevels(RAIN_FROM_INDOORS_ENVELOPE_B64)
        )
    )

    fun findById(id: String): PlaybackTrack? = tracks.firstOrNull { it.id == id }

    private fun decodeDbfsLevels(base64: String): FloatArray {
        val bytes = Base64.decode(base64, Base64.DEFAULT)
        return FloatArray(bytes.size) { index ->
            val normalized = (bytes[index].toInt() and 0xFF) / 255f
            (-80f + (normalized * 80f)).coerceIn(-80f, 0f)
        }
    }

    private const val RAIN_FROM_INDOORS_ENVELOPE_B64 = ""
}
